// ... existing imports ...

function ColorGame({ onNext }) {
  // ... existing code ...

  return (
    <div style={{
      backgroundImage: 'url("https://images.unsplash.com/photo-1633356122544-f134324ef6db?w=1200&h=800&fit=crop")',
      backgroundSize: 'cover',
      backgroundPosition: 'center',
      backgroundAttachment: 'fixed',
      minHeight: '100vh',
      paddingTop: '50px',
      textAlign: 'center',
      position: 'relative',
    }}>
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: 'rgba(255, 250, 205, 0.72)',
        zIndex: 0,
      }} />
      <div style={{ position: 'relative', zIndex: 1 }}>
        <h1>Match Colors 🌈</h1>

        {/* Draggable Colors */}
        <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center", marginBottom: "40px" }}>
          {colors.map(color => (
            <div
              key={color}
              draggable
              onDragStart={(e) => e.dataTransfer.setData("color", color)}
              style={{
                fontSize: "40px",
                margin: "10px",
                cursor: "grab",
              }}
            >
              {colorEmojis[color]}
            </div>
          ))}
        </div>

        {/* Drop Boxes */}
        <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center" }}>
          {shuffledBoxes.map(boxColor => (
            <div
              key={boxColor}
              onDragOver={(e) => e.preventDefault()}
              onDrop={(e) => {
                const draggedColor = e.dataTransfer.getData("color");
                handleDrop(draggedColor, boxColor);
              }}
              style={{
                width: "150px",
                height: "150px",
                backgroundColor: matched.has(boxColor) ? boxBackgrounds[boxColor] : "gray",
                margin: "10px",
                lineHeight: "150px",
                border: matched.has(boxColor) ? "5px solid green" : "2px solid #ccc",
                position: "relative",
                borderRadius: "10px",
              }}
            >
              {boxColor.charAt(0).toUpperCase() + boxColor.slice(1)} Box
              {matched.has(boxColor) && <span style={{ position: "absolute", top: "5px", right: "5px", fontSize: "30px" }}>✅</span>}
            </div>
          ))}
        </div>

        {/* Complete Task Button */}
        <button
          onClick={handleCompleteTask}
          style={{
            fontSize: "18px",
            padding: "12px 25px",
            backgroundColor: "#FF6B6B",
            color: "white",
            border: "none",
            borderRadius: "10px",
            cursor: "pointer",
            marginTop: "30px",
            fontWeight: "bold",
          }}
        >
          Complete Task ✔️
        </button>

        {/* Message Display */}
        {showMessage && (
          <div style={{
            marginTop: "30px",
            padding: "20px",
            backgroundColor: isSuccess ? "#90EE90" : "#FFB6C6",
            borderRadius: "10px",
            fontSize: "24px",
            fontWeight: "bold",
            color: isSuccess ? "#006400" : "#8B0000",
            minHeight: "80px",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            marginLeft: "20px",
            marginRight: "20px",
          }}>
            {taskMessage}
          </div>
        )}

        {/* Next Button - Only on Success */}
        {showMessage && isSuccess && (
          <button
            onClick={() => onNext && onNext()}
            style={{
              fontSize: "20px",
              padding: "15px 30px",
              backgroundColor: "#4CAF50",
              color: "white",
              border: "none",
              borderRadius: "10px",
              cursor: "pointer",
              marginTop: "20px",
              fontWeight: "bold",
            }}
          >
            Next ➡️
          </button>
        )}
      </div>
    </div>
  );
}

export default ColorGame;
